/* ------------------------------------------------------------------ */
/* Utilities                                                          */
/* ------------------------------------------------------------------ */

function hashSeed(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = (h << 5) - h + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

function mulberry32(seed) {
  let a = seed;
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

const PALETTE = [
  ["#14E0C4", "#0B8F7C"],
  ["#FF4F8B", "#B8285C"],
  ["#B8863B", "#7A5A22"],
  ["#6C7BFF", "#3A44B0"],
  ["#F2C14E", "#B98B1E"],
];

function formatDate(iso) {
  if (!iso) return "";
  const d = new Date(iso + "T00:00:00");
  const months = ["JAN","FEB","MAR","APR","MAY","JUN","JUL","AUG","SEP","OCT","NOV","DEC"];
  return `${String(d.getDate()).padStart(2, "0")} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

function todayISO() {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}

/* ------------------------------------------------------------------ */
/* Generative placeholder art                                         */
/* ------------------------------------------------------------------ */

function GenerativeArt({ seed, colors }) {
  const rand = useMemo(() => mulberry32(hashSeed(seed)), [seed]);
  const shapes = useMemo(() => {
    const arr = [];
    const n = 4 + Math.floor(rand() * 3);
    for (let i = 0; i < n; i++) {
      arr.push({
        cx: rand() * 100,
        cy: rand() * 100,
        r: 18 + rand() * 34,
        c: i % 2 === 0 ? colors[0] : colors[1],
        o: 0.35 + rand() * 0.4,
      });
    }
    return arr;
  }, [rand, colors]);

  return (
    <svg viewBox="0 0 100 100" width="100%" height="100%" preserveAspectRatio="xMidYMid slice">
      <rect width="100" height="100" fill="#0F1626" />
      {shapes.map((s, i) => (
        <circle key={i} cx={s.cx} cy={s.cy} r={s.r} fill={s.c} opacity={s.o} />
      ))}
      <rect width="100" height="100" fill="url(#grain)" opacity="0.15" />
    </svg>
  );
}

