function SettingsSheet({ onClose, userName, avatar, theme, lang, onSave, t }) {
  const [nameInput, setNameInput] = useState(userName);
  const [avatarPreview, setAvatarPreview] = useState(avatar);
  const [selectedTheme, setSelectedTheme] = useState(theme);
  const [selectedLang, setSelectedLang] = useState(lang);
  const fileRef = useRef(null);

  function handleAvatar(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setAvatarPreview(ev.target.result);
    reader.readAsDataURL(file);
  }

  function handleSave() {
    onSave({ userName: nameInput.trim() || t.bioDefaultName, avatar: avatarPreview, theme: selectedTheme, lang: selectedLang });
    onClose();
  }

  return (
    <div className="sheet-backdrop" onClick={onClose}>
      <div className="sheet" onClick={(e) => e.stopPropagation()}>
        <div className="sheet-header">
          <h2>{t.settingsTitle}</h2>
          <button className="icon-btn" onClick={onClose} aria-label="Close">
            <X size={18} />
          </button>
        </div>

        <div className="settings-avatar-row">
          <div className="settings-avatar" onClick={() => fileRef.current?.click()}>
            {avatarPreview ? (
              <img src={avatarPreview} alt="Profile" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} />
            ) : (
              <svg viewBox="0 0 100 100" width="100%" height="100%">
                <rect width="100" height="100" fill="#0F1626" />
                <circle cx="50" cy="40" r="18" fill="#2B3A5C" />
                <path d="M20 90 Q50 55 80 90 Z" fill="#2B3A5C" />
              </svg>
            )}
            <div className="settings-avatar-overlay">{t.settingsAvatarChange}</div>
          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleAvatar} />
        </div>

        <label className="field">
          <span>{t.settingsDisplayName}</span>
          <input
            value={nameInput}
            onChange={(e) => setNameInput(e.target.value)}
            placeholder={t.settingsNamePlaceholder}
          />
        </label>

        <div className="field">
          <span>{t.settingsBackground}</span>
          <div className="theme-toggle">
            <button className={`theme-btn ${selectedTheme === "dark" ? "theme-btn-active" : ""}`} onClick={() => setSelectedTheme("dark")}>
              {t.settingsDark}
            </button>
            <button className={`theme-btn ${selectedTheme === "light" ? "theme-btn-active" : ""}`} onClick={() => setSelectedTheme("light")}>
              {t.settingsLight}
            </button>
          </div>
        </div>

        <div className="field">
          <span>{t.settingsLanguage}</span>
          <div className="lang-toggle">
            {Object.keys(LANG_LABELS).map((code) => (
              <button
                key={code}
                className={`theme-btn ${selectedLang === code ? "theme-btn-active" : ""}`}
                onClick={() => setSelectedLang(code)}
              >
                {LANG_LABELS[code]}
              </button>
            ))}
          </div>
        </div>

        <button className="solid-btn" onClick={handleSave}>
          <Check size={15} /> {t.settingsSave}
        </button>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Catalog                                                            */
/* ------------------------------------------------------------------ */

const CATALOG = {
  CHROMA14: { title: "Chromatic Drift", artist: "N. Osei", venue: "Biennale — Gallery Sigma" },
  FAULT02: { title: "Fault Lines", artist: "M. Duarte", venue: "Museum of Other Worlds" },
  HOLLOW21: { title: "Hollow Choir", artist: "R. Venn", venue: "Studio Aperture" },
  ECHO07: { title: "Echo Garden", artist: "T. Lindqvist", venue: "Nomad Pavilion" },
  VOID99: { title: "Voidwalk", artist: "K. Amaro", venue: "Lattice Museum" },
  BURA01: { title: "Bura Ceramics", artist: "Niger", venue: "AABC" },
  DAVID01: { title: "David", artist: "Michelangelo", venue: "Galleria dell'Accademia" },
};

function normalizeCode(raw) {
  return (raw || "").trim().toUpperCase().replace(/[\s-]/g, "");
}

/* ------------------------------------------------------------------ */
/* Scan sheet                                                         */
/* ------------------------------------------------------------------ */

function ScanSheet({ onClose, onResolve, alreadyStamped, t }) {
  const [tab, setTab] = useState("scan");
  const [codeInput, setCodeInput] = useState("");
  const [error, setError] = useState("");
  const [scanning, setScanning] = useState(false);
  const [cameraError, setCameraError] = useState("");
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const rafRef = useRef(null);
  const detectorRef = useRef(null);
  const resolvedRef = useRef(false);

  const supportsDetector = typeof window !== "undefined" && "BarcodeDetector" in window;

  const tryResolve = useCallback(
    (rawCode) => {
      const code = normalizeCode(rawCode);
      const entry = CATALOG[code];
      if (!entry) {
        setError(t.errorNotFound(rawCode));
        return false;
      }
      if (alreadyStamped(code)) {
        setError(t.errorAlreadyStamped(entry.title));
        return false;
      }
      resolvedRef.current = true;
      onResolve(code, entry);
      return true;
    },
    [alreadyStamped, onResolve, t]
  );

  function handleCodeSubmit(e) {
    e.preventDefault();
    setError("");
    tryResolve(codeInput);
  }

  useEffect(() => {
    if (tab !== "scan") return;
    if (!supportsDetector) {
      setCameraError(t.scanBrowserError);
      return;
    }
    let cancelled = false;

    async function start() {
      setCameraError("");
      try {
        detectorRef.current = new window.BarcodeDetector({ formats: ["qr_code"] });
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "environment" } });
        if (cancelled) { stream.getTracks().forEach((t) => t.stop()); return; }
        streamRef.current = stream;
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          await videoRef.current.play();
        }
        setScanning(true);
        loop();
      } catch (err) {
        setCameraError(t.scanCameraError);
      }
    }

    async function loop() {
      if (cancelled || !videoRef.current || !detectorRef.current) return;
      try {
        const codes = await detectorRef.current.detect(videoRef.current);
        if (codes && codes.length && !resolvedRef.current) {
          const ok = tryResolve(codes[0].rawValue);
          if (ok) return;
        }
      } catch (err) {
        // transient decode errors are expected between frames
      }
      rafRef.current = requestAnimationFrame(loop);
    }

    start();
    return () => {
      cancelled = true;
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop());
      setScanning(false);
    };
  }, [tab, supportsDetector, tryResolve, t]);

  return (
    <div className="sheet-backdrop" onClick={onClose}>
      <div className="sheet" onClick={(e) => e.stopPropagation()}>
        <div className="sheet-header">
          <h2>{t.addStampTitle}</h2>
          <button className="icon-btn" onClick={onClose} aria-label="Close">
            <X size={18} />
          </button>
        </div>

        <div className="tabs">
          <button className={`tab ${tab === "scan" ? "tab-active" : ""}`} onClick={() => { setTab("scan"); setError(""); }}>
            <QrCode size={15} /> {t.scanQR}
          </button>
          <button className={`tab ${tab === "code" ? "tab-active" : ""}`} onClick={() => { setTab("code"); setError(""); }}>
            <Keyboard size={15} /> {t.enterCode}
          </button>
        </div>

        {tab === "scan" ? (
          <div className="scan-area">
            {!cameraError ? (
              <div className="scan-video-wrap">
                <video ref={videoRef} className="scan-video" muted playsInline />
                <div className="scan-frame">
                  <span className="corner tl" /><span className="corner tr" />
                  <span className="corner bl" /><span className="corner br" />
                </div>
                {scanning && (
                  <div className="scan-status">
                    <Loader2 size={13} className="spin" /> {t.scanInstruction}
                  </div>
                )}
              </div>
            ) : (
              <div className="scan-fallback">
                <QrCode size={26} strokeWidth={1.2} />
                <p>{cameraError}</p>
              </div>
            )}
          </div>
        ) : (
          <form onSubmit={handleCodeSubmit}>
            <label className="field">
              <span>{t.artworkCode}</span>
              <input
                value={codeInput}
                onChange={(e) => setCodeInput(e.target.value)}
                placeholder={t.artworkCodePlaceholder}
                autoCapitalize="characters"
              />
            </label>
            <button className="solid-btn" type="submit">
              <Check size={15} /> {t.stampPassport}
            </button>
          </form>
        )}

        {error && <div className="field-error">{error}</div>}
        <p className="sheet-hint">{t.scanHint}</p>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Book                                                               */
/* ------------------------------------------------------------------ */

const STAMPS_PER_PAGE = 2;

function buildPages(stamps) {
  const pages = [{ type: "bio" }];
  for (let i = 0; i < stamps.length; i += STAMPS_PER_PAGE) {
    pages.push({ type: "stamps", items: stamps.slice(i, i + STAMPS_PER_PAGE), startIndex: i });
  }
  if (stamps.length % STAMPS_PER_PAGE === 0) {
    pages.push({ type: "stamps", items: [], startIndex: stamps.length });
  }
  pages.push({ type: "back" });
  return pages;
}

function Book({ stamps, onRequestAdd, userName, avatar, t }) {
  const [open, setOpen] = useState(false);
  const [current, setCurrent] = useState(0);
  const [flip, setFlip] = useState(null);

  const pages = useMemo(() => buildPages(stamps), [stamps]);

  useEffect(() => {
    if (current > pages.length - 1) setCurrent(pages.length - 1);
  }, [pages.length, current]);

  const goTo = useCallback(
    (dir) => {
      if (flip) return;
      const to = dir === "next" ? current + 1 : current - 1;
      if (to < 0 || to > pages.length - 1) return;
      setFlip({ dir, from: current, to, active: false });
      requestAnimationFrame(() => requestAnimationFrame(() => setFlip((f) => (f ? { ...f, active: true } : f))));
    },
    [current, flip, pages.length]
  );

  function onTransitionEnd() {
    if (flip && flip.active) { setCurrent(flip.to); setFlip(null); }
  }

  function renderPage(p) {
    if (!p) return null;
    if (p.type === "bio") return <BioPage stamps={stamps} userName={userName} avatar={avatar} t={t} />;
    if (p.type === "stamps") return <StampsPage items={p.items} startIndex={p.startIndex} t={t} />;
    return <BackCoverPage onAdd={onRequestAdd} t={t} />;
  }

  const baseIndex = flip ? flip.to : current;

  return (
    <div className="book-wrap">
      <div className={`cover ${open ? "cover-open" : ""}`} onClick={() => !open && setOpen(true)}>
        <CoverFace t={t} />
      </div>

      {open && (
        <div className="book">
          <div className="page-base">{renderPage(pages[baseIndex])}</div>
          {flip && (
            <div
              className={`page-flip ${flip.dir === "next" ? "origin-left" : "origin-right"} ${flip.active ? (flip.dir === "next" ? "spin-next" : "spin-prev") : ""}`}
              onTransitionEnd={onTransitionEnd}
            >
              {renderPage(pages[flip.from])}
            </div>
          )}
          <button className="nav-btn nav-left" onClick={() => goTo("prev")} disabled={current === 0} aria-label="Previous page">
            <ChevronLeft size={18} />
          </button>
          <button className="nav-btn nav-right" onClick={() => goTo("next")} disabled={current === pages.length - 1} aria-label="Next page">
            <ChevronRight size={18} />
          </button>
          <div className="page-indicator">
            {String(current + 1).padStart(2, "0")} / {String(pages.length).padStart(2, "0")}
          </div>
        </div>
      )}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Seed data                                                          */
/* ------------------------------------------------------------------ */

const SEED_STAMPS = [
  { id: "CHROMA14-2026-05-14", code: "CHROMA14", title: "Chromatic Drift", artist: "N. Osei", venue: "Biennale — Gallery Sigma", date: "2026-05-14", image: null },
  { id: "FAULT02-2026-06-02", code: "FAULT02", title: "Fault Lines", artist: "M. Duarte", venue: "Museum of Other Worlds", date: "2026-06-02", image: null },
  { id: "HOLLOW21-2026-06-21", code: "HOLLOW21", title: "Hollow Choir", artist: "R. Venn", venue: "Studio Aperture", date: "2026-06-21", image: null },
];

const STORAGE_KEY = "vr-art-passport:stamps";

/* ------------------------------------------------------------------ */
/* App                                                                */
/* ------------------------------------------------------------------ */

export default function App() {
  const [stamps, setStamps] = useState(SEED_STAMPS);
  const [showScan, setShowScan] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [toast, setToast] = useState("");
  const [userName, setUserName] = useState("Explorer");
  const [avatar, setAvatar] = useState(null);
  const [theme, setTheme] = useState("dark");
  const [lang, setLang] = useState("en");

  const t = TRANSLATIONS[lang];

  useEffect(() => {
    (async () => {
      try {
        const result = await window.storage?.get(STORAGE_KEY, false);
        if (result?.value) {
          const parsed = JSON.parse(result.value);
          if (Array.isArray(parsed) && parsed.length) setStamps(parsed);
        }
      } catch (e) {
        // no saved data yet — keep seed stamps
      } finally {
        setLoaded(true);
      }
    })();
  }, []);

  async function persist(next) {
    try {
      await window.storage?.set(STORAGE_KEY, JSON.stringify(next), false);
    } catch (e) {
      // storage unavailable
    }
  }

  function alreadyStamped(code) {
    const today = todayISO();
    return stamps.some((s) => s.code === code && s.date === today);
  }

  function handleResolve(code, entry) {
    const date = todayISO();
    const stamp = {
      id: `${code}-${date}-${Date.now()}`,
      code,
      title: entry.title,
      artist: entry.artist,
      venue: entry.venue,
      date,
      image: null,
    };
    const next = [...stamps, stamp].sort((a, b) => (a.date < b.date ? -1 : 1));
    setStamps(next);
    persist(next);
    setShowScan(false);
    setToast(t.toastStamped(stamp.title));
    setTimeout(() => setToast(""), 2200);
  }

  function handleSaveSettings({ userName: newName, avatar: newAvatar, theme: newTheme, lang: newLang }) {
    setUserName(newName);
    setAvatar(newAvatar);
    setTheme(newTheme);
    setLang(newLang);
    const nextT = TRANSLATIONS[newLang];
    setToast(nextT.toastSettingsSaved);
    setTimeout(() => setToast(""), 2000);
  }

  return (
    <div className="app-root">
      <style>{CSS}</style>
<div className={`phone-frame theme-${theme}`}>
        <div className="status-bar">
          <span>9:41</span>
          <span className="status-icons">••• 5G 100%</span>
        </div>
        <div className="app-header">
          <span className="app-title">VANGO</span>
          <div className="header-actions">
            <button className="header-settings" onClick={() => setShowSettings(true)} aria-label="Settings">
              <Settings size={16} />
            </button>
            <button className="header-add" onClick={() => setShowScan(true)} aria-label="Add stamp">
              <Plus size={18} />
            </button>
          </div>
        </div>

        <div className="app-body">
          {!loaded ? (
            <div className="loading-state">
              <BookOpen size={26} strokeWidth={1.3} />
              <span>{t.loading}</span>
            </div>
          ) : (
            <Book stamps={stamps} onRequestAdd={() => setShowScan(true)} userName={userName} avatar={avatar} t={t} />
          )}
        </div>

        {toast && <div className="toast">{toast}</div>}
      </div>

      {showScan && <ScanSheet onClose={() => setShowScan(false)} onResolve={handleResolve} alreadyStamped={alreadyStamped} t={t} />}
      {showSettings && (
        <SettingsSheet
          onClose={() => setShowSettings(false)}
          userName={userName}
          avatar={avatar}
          theme={theme}
          lang={lang}
          onSave={handleSaveSettings}
          t={t}
        />
      )}
    </div>
  );
}

